import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,a as e}from"./app-371d233c.js";const t="/assets/images/vasvari/springboot/dependency_injection.webp",o={},l=e('<h1 id="a-dependency-injection" tabindex="-1"><a class="header-anchor" href="#a-dependency-injection" aria-hidden="true">#</a> A Dependency Injection</h1><p>Megnézzük, mi az a <strong>Dependency Injection</strong> (<em>DI</em>) és hogyan használhatjuk a Spring Boot keretrendszerrel. A Spring Boot keretrendszer biztosítja a <strong>DI</strong>-t ezért jó ha megismerjük az alapokat. A <strong>DI</strong> lehetővé teszi a komponensek közötti laza csatolást, így a kód rugalmasabbá, karbantarthatóbbá és tesztelhetőbbé válik.</p><p>Az alábbi témákat fogjuk tárgyalni:</p><ul><li>A <strong>Dependency Injection</strong> bemutatása</li><li>A <strong>Dependency Injection</strong> használata a Spring Bootban</li></ul><h2 id="bevezetese" tabindex="-1"><a class="header-anchor" href="#bevezetese" aria-hidden="true">#</a> Bevezetése</h2><p>A <strong>Dependency Injection</strong> egy olyan szoftverfejlesztési technika, amellyel olyan objektumokat hozhatunk létre amelyek más objektumoktól függenek. A <strong>DI</strong> segít az osztályok közötti interakcióban, ugyanakkor az osztályok függetlenségét is megőrzi.</p><p>A <strong>Dependency Injection</strong>-ben háromféle osztály létezik:</p><ul><li>A szolgáltatás (<strong>service</strong>) egy olyan osztály, amelyet használhatunk (<em>ez a függőség - dependency</em>).</li><li>A kliens (<strong>client</strong>) egy olyan osztály, amely használja a függőséget (<strong>dependency</strong>-t).</li><li>Az injektor átadja a függőséget (<strong>a szolgáltatást - service</strong>) a függő osztálynak (<strong>a kliens - client</strong>).</li></ul><figure><img src="'+t+`" alt="1. ábra: A Dependency Injection összekapcsolja az osztályokat." tabindex="0" loading="lazy"><figcaption><strong>1. ábra:</strong> A Dependency Injection összekapcsolja az osztályokat.</figcaption></figure><p>Nézzünk meg egy egyszerűsített példát a <strong>Dependency Injection</strong> használatára Java kóddal. A következő kódban nincs <strong>Dependency Injection</strong>, mert a <code>Car</code> kliens (<strong>client</strong>) osztály egy objektumot hoz létre a szolgáltatás (<strong>service</strong>) osztályból :</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Car</span> <span class="token punctuation">{</span> 
  <span class="token keyword">private</span> <span class="token class-name">Owner</span> owner<span class="token punctuation">;</span> 

  <span class="token keyword">public</span> <span class="token class-name">Car</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    owner <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Owner</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> 
  <span class="token punctuation">}</span> 
<span class="token punctuation">}</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A következő kódban a szolgáltatás (<strong>service</strong>) objektum nem közvetlenül a kliens (<strong>client</strong>) osztályban jön létre. Az osztály konstruktorában paraméterként kerül átadásra:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Car</span> <span class="token punctuation">{</span> 
  <span class="token keyword">private</span> <span class="token class-name">Owner</span> owner<span class="token punctuation">;</span> 

  <span class="token keyword">public</span> <span class="token class-name">Car</span><span class="token punctuation">(</span><span class="token class-name">Owner</span> owner<span class="token punctuation">)</span>  <span class="token punctuation">{</span> 
    <span class="token keyword">this</span><span class="token punctuation">.</span>owner <span class="token operator">=</span> owner<span class="token punctuation">;</span> 
  <span class="token punctuation">}</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A <strong>Dependency Injection</strong>-nek különböző típusai vannak. Nézzünk meg közülük kettőt:</p><ul><li><strong>Constructor injection:</strong> Függőségek átadása a kliens (<strong>client</strong>) osztály konstruktorának. A Constructor injection egy példáját már láthattuk az előző <code>Car</code> osztály kódjában. Kötelező függőségek esetén ajánlott használni. Minden függőséget az osztály konstruktorával adunk meg és egy objektum nem hozható létre a szükséges függőségek nélkül.</li><li><strong>Setter injection:</strong> Függőséget setter metóduson keresztül biztosítjuk. A következő kód egy példát mutat a <em>setter injection</em>-re:</li></ul><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Car</span> <span class="token punctuation">{</span> 
  <span class="token keyword">private</span> <span class="token class-name">Owner</span> owner<span class="token punctuation">;</span> 

  <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setOwner</span><span class="token punctuation">(</span><span class="token class-name">Owner</span> owner<span class="token punctuation">)</span> <span class="token punctuation">{</span> 
    <span class="token keyword">this</span><span class="token punctuation">.</span>owner <span class="token operator">=</span> owner<span class="token punctuation">;</span> 
  <span class="token punctuation">}</span> 
<span class="token punctuation">}</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Itt a függőséget most paraméterként adjuk át a <em>setter</em>-nek. A <em>setter injection</em> rugalmasabb, mert az objektumok létrehozhatók az összes függőségük nélkül is. Ez a megközelítés lehetővé teszi az opcionális függőségek használatát.</p><p>A <strong>DI</strong> csökkenti a függőségeket a kódban és újrafelhasználhatóbbá teszi a kódot. Emellett javítja a kód tesztelhetőségét is. Most megismertük a <strong>DI</strong> alapjait. Ezután megnézzük hogyan használják a <strong>DI</strong>-t a Spring Bootban.</p><h2 id="di-spring-bootban" tabindex="-1"><a class="header-anchor" href="#di-spring-bootban" aria-hidden="true">#</a> DI Spring Bootban</h2><p>A Spring keretrendszerben az <em>ApplicationContext</em> felelős az objektumok és függőségeik létrehozásáért és kezeléséért. A Spring Boot regisztrálja az annotációkkal (<code>@Service</code>, <code>@Repository</code>, <code>@Controller</code>, stb.) ellátott osztályokat melyeket aztán <strong>Dependency Injection</strong>-nel lehet használni.</p><p>A Spring Boot több <strong>Dependency Injection</strong> típust támogat és a leggyakrabban használtak közé tartoznak a következők:</p><ul><li><p><strong>Constructor injection:</strong></p><p>A <em>constructor injection</em>-nel már korábban találkoztunk így jelenlegi kontextusban sem hoz számunkra újdonságot.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// Constructor injection</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Car</span> <span class="token punctuation">{</span>
  <span class="token keyword">private</span> <span class="token keyword">final</span> <span class="token class-name">CarRepository</span> carRepository<span class="token punctuation">;</span>

  <span class="token keyword">public</span> <span class="token class-name">Car</span><span class="token punctuation">(</span><span class="token class-name">CarRepository</span> carRepository<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">this</span><span class="token punctuation">.</span>carRepository <span class="token operator">=</span> carRepository<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
      
  <span class="token comment">// Fetch all cars from db </span>
  carRepository<span class="token punctuation">.</span><span class="token function">findAll</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Viszont</strong>, ha több konstruktor van az osztályban akkor a <code>@Autowired</code> megjegyzést kell használnunk annak meghatározására, hogy melyik konstruktort használjuk a <strong>DI</strong>-hez:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// Constructor to used for dependency injection</span>
<span class="token annotation punctuation">@Autowired</span>  
<span class="token keyword">public</span> <span class="token class-name">Car</span><span class="token punctuation">(</span><span class="token class-name">CarRepository</span> carRepository<span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>carRepository <span class="token operator">=</span> carRepository<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>Setter injection:</strong></p><p>A <strong>DI</strong> a setter metódusokon keresztül történik. A <em>setter injection</em> akkor hasznos, ha opcionális függőségek vannak vagy ha a függőségeket futás közben akarjuk módosítani. Az alábbiakban egy példa a <em>setter injectionre</em>:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// Setter injection</span>
<span class="token annotation punctuation">@Service</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">AppUserService</span> <span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token class-name">AppUserRepository</span> userRepository<span class="token punctuation">;</span>

    <span class="token annotation punctuation">@Autowired</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setAppUserRepository</span><span class="token punctuation">(</span><span class="token class-name">AppUserRepository</span> userRepository<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>userRepository <span class="token operator">=</span> userRepository<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token comment">// Other methods that use userRepository</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><strong>Field injection:</strong></p><p>A <strong>DI</strong> közvetlenül a mezőkbe kerülnek befecskendezésre. A <em>field injection</em> előnye az egyszerűsége, de van néhány hátránya is. Futásidejű hibákat okozhat, ha a függőség nem áll rendelkezésre. Íme egy példa:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// Field injection</span>
<span class="token annotation punctuation">@Service</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">CarDatabaseService</span> <span class="token keyword">implements</span> <span class="token class-name">CarService</span> <span class="token punctuation">{</span>
  <span class="token comment">// Car database services</span>
<span class="token punctuation">}</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">CarController</span> <span class="token punctuation">{</span>
  <span class="token annotation punctuation">@Autowired</span>
  <span class="token keyword">private</span> <span class="token class-name">CarDatabaseService</span> carDatabaseService<span class="token punctuation">;</span>
  <span class="token comment">//...</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A következő részben megvizsgáljuk, hogyan lehet használni a <strong>Java Persistent API</strong> (<em>JPA</em>)-t a Spring Boot alkalmazással, valamint hogyan lehet beállítani egy <strong>H2</strong> adatbázist. Továbbá megismerjük a <strong>CRUD</strong> repository-k létrehozását és a táblák közötti kapcsolatot.</p></li></ul>`,22),i=[l];function p(c,r){return s(),a("div",null,i)}const u=n(o,[["render",p],["__file","lesson4c.html.vue"]]);export{u as default};
